fn run() {
    input! {
        a: (u32, u32),
        b: (u32, u32),
        s: chars,
    }
    let mut f = 0;
    f += s[0].to_digit(10).unwrap() * 10 * 60;
    f += s[1].to_digit(10).unwrap() * 60;
    f += s[3].to_digit(10).unwrap() * 10;
    f += s[4].to_digit(10).unwrap();
    assert!((f - 300) % a.0 == 0);
    let start = f;
    let end = start + a.1;
    let mut p = 300;
    let mut ans = 0;
    while p < 24 * 60 {
        let (s, e) = (p, p + b.1);
        let (l, r) = (std::cmp::max(s, start), std::cmp::min(e, end));
        if l < r {
            ans += 1;
        }
        p += b.0;
    }
    println!("{}", ans);
}

fn main() {
    run();
}
